import fs from 'fs'
import path from 'path'
import { generateText } from 'ai'

const COMPRESS_SYSTEM = `你是一个对话压缩器。你只输出 JSON，不输出任何其他内容。`

const COMPRESS_USER_TEMPLATE = `请压缩以下对话历史，完成两个任务：

任务一：压缩成一段简洁的摘要（不超过 500 字）。
- 保留关键事实：人名、数字、决策结论、文件路径
- 保留用户偏好
- 丢弃寒暄、重复确认、中间推理过程

任务二：提取 3-5 条值得长期记住的关键事实。

直接输出 JSON，不要用 markdown 代码块包裹，不要输出任何解释：
{"summary": "摘要", "memories": ["事实1", "事实2"]}

<conversation>
%CONVERSATION%
</conversation>`

function serializeContent(content) {
  if (typeof content === 'string') return content
  if (!Array.isArray(content)) return JSON.stringify(content)
  return content
    .map(part => {
      if (typeof part === 'string') return part
      if (part.type === 'text') return part.text
      if (part.type === 'tool-call')
        return `[调用工具 ${part.toolName}(${JSON.stringify(part.args)})]`
      if (part.type === 'tool-result') {
        const result = String(part.result)
        if (result.length <= 200) return `[工具结果] ${result}`
        return `[工具结果] ${result.slice(0, 200)}...(省略${result.length - 200}字符)`
      }
      return ''
    })
    .filter(Boolean)
    .join('\n')
}

export async function compress(
  messages,
  { keepRecent = 2, model, workspacePath } = {}
) {
  const sessionsDir = path.join(workspacePath, 'sessions')
  fs.mkdirSync(sessionsDir, { recursive: true })

  // 1. 持久化：完整历史写入 raw.jsonl
  const rawPath = path.join(sessionsDir, 'raw.jsonl')
  fs.appendFileSync(rawPath, JSON.stringify(messages) + '\n')
  console.log(
    `  [Compress] Persisting ${messages.length} messages to sessions/raw.jsonl`
  )

  // 2. 切分：保留最近 keepRecent 条，其余压缩
  const toCompress = messages.slice(0, -keepRecent)
  const toKeep = messages.slice(-keepRecent)

  // 3. 用 LLM 生成摘要 + 提取记忆
  const conversationText = toCompress
    .map(m => {
      const content = serializeContent(m.content)
      return `[${m.role}] ${content}`
    })
    .join('\n')

  const { text } = await generateText({
    model,
    system: COMPRESS_SYSTEM,
    prompt: COMPRESS_USER_TEMPLATE.replace('%CONVERSATION%', conversationText),
  })

  let summary, memories
  try {
    const jsonMatch = text.match(/\{[\s\S]*"summary"[\s\S]*\}/)
    const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : text)
    summary = parsed.summary
    memories = parsed.memories || []
  } catch {
    console.log('  [Compress] Warning: JSON parse failed, using raw text as summary')
    summary = text.slice(0, 500)
    memories = []
  }

  // 4. 更新记忆索引
  if (memories.length > 0) {
    const memoryPath = path.join(workspacePath, 'memory', 'MEMORY.md')
    const today = new Date().toISOString().split('T')[0]
    const newEntries = memories.map(m => `- [${today}] ${m}`).join('\n')

    let existing = ''
    try {
      existing = fs.readFileSync(memoryPath, 'utf-8')
    } catch {
      existing = '# 记忆索引\n'
    }

    // 200 行上限
    const lines = existing.split('\n')
    const entryLines = newEntries.split('\n')
    if (lines.length + entryLines.length > 200) {
      const overflow = lines.length + entryLines.length - 200
      const headerEnd = lines.findIndex(l => l.startsWith('- '))
      if (headerEnd !== -1) {
        lines.splice(headerEnd, overflow)
      }
    }

    fs.writeFileSync(memoryPath, lines.join('\n').trimEnd() + '\n' + newEntries + '\n')
    console.log(
      `  [Compress] Updating memory/MEMORY.md (+${memories.length} entries)`
    )
  }

  // 5. 摘要替换旧消息
  const compressed = [
    { role: 'assistant', content: `[对话摘要]\n${summary}` },
    ...toKeep,
  ]

  // 6. 快照
  const ctxPath = path.join(sessionsDir, 'ctx.json')
  fs.writeFileSync(ctxPath, JSON.stringify(compressed, null, 2))

  return compressed
}

import readline from 'readline'
import path from 'path'
import fs from 'fs'
import { fileURLToPath } from 'url'
import { generateText, tool } from 'ai'
import { createAnthropic } from '@ai-sdk/anthropic'
import { z } from 'zod'
import { execSync } from 'child_process'
import { bootstrap } from './bootstrap.js'
import { prune } from './prune.js'
import { compress } from './compress.js'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const WORKSPACE_PATH = path.join(__dirname, 'workspace')

const anthropic = createAnthropic({
  baseURL: 'http://localhost:3002',
  apiKey: process.env.ANTHROPIC_API_KEY,
})
const model = anthropic('claude-sonnet-4-6')

const TOKEN_THRESHOLD = 6000
const MAX_ITERATIONS = 10

// ── 工具定义 ─────────────────────────────────────────────────────────────────
const tools = {
  bash: tool({
    description: '执行 shell 命令，返回 stdout',
    parameters: z.object({
      command: z.string().describe('要执行的 shell 命令'),
    }),
    execute: async ({ command }) => {
      try {
        return execSync(command, { encoding: 'utf-8', timeout: 10000 }).trim()
      } catch (e) {
        return `执行失败: ${e.message}`
      }
    },
  }),

  read_file: tool({
    description: '读取指定路径的文件内容',
    parameters: z.object({
      path: z.string().describe('文件路径'),
    }),
    execute: async ({ path: filePath }) => {
      try {
        return fs.readFileSync(filePath, 'utf-8')
      } catch (e) {
        return `读取失败: ${e.message}`
      }
    },
  }),

  write_file: tool({
    description: '将内容写入指定路径的文件',
    parameters: z.object({
      path: z.string().describe('文件路径'),
      content: z.string().describe('要写入的内容'),
    }),
    execute: async ({ path: filePath, content }) => {
      try {
        fs.mkdirSync(path.dirname(filePath), { recursive: true })
        fs.writeFileSync(filePath, content)
        return `已写入 ${filePath}`
      } catch (e) {
        return `写入失败: ${e.message}`
      }
    },
  }),
}

// ── ReAct 循环 ───────────────────────────────────────────────────────────────
let lastPromptTokens = 0

async function chat(messages, systemPrompt) {
  // 1. 先剪枝：无成本的字符串截断，立即缩减 token
  const pruned = prune(messages)
  messages.length = 0
  messages.push(...pruned)

  // 2. 再压缩：剪枝后仍超阈值才触发（需要 LLM 调用）
  if (lastPromptTokens > TOKEN_THRESHOLD) {
    const before = lastPromptTokens
    const compressed = await compress(messages, {
      keepRecent: 2,
      model,
      workspacePath: WORKSPACE_PATH,
    })
    messages.length = 0
    messages.push(...compressed)
    console.log(`  [Compress] ${before} → (compressed, awaiting next LLM call)`)
    lastPromptTokens = 0
  }

  for (let i = 1; i <= MAX_ITERATIONS; i++) {

    const { steps, text, response, usage } = await generateText({
      model,
      system: systemPrompt,
      messages,
      tools,
      maxSteps: 1,
    })

    // 记录本次 prompt token 数
    if (usage) {
      lastPromptTokens = usage.promptTokens
    }

    const step = steps[0]
    if (!step) return text

    if (step.toolCalls.length === 0) {
      return step.text
    }

    for (const tc of step.toolCalls) {
      const result = step.toolResults.find(
        r => r.toolCallId === tc.toolCallId
      )
      console.log(
        `  [Step ${i}] Tool: ${tc.toolName}(${JSON.stringify(tc.args)})`
      )
      if (result) {
        const preview = String(result.result).slice(0, 120)
        console.log(
          `           Result: ${preview}${String(result.result).length > 120 ? '...' : ''}`
        )
      }
    }

    messages.push(...response.messages)
  }

  return '（达到最大迭代次数）'
}

// ── REPL ─────────────────────────────────────────────────────────────────────
async function main() {
  const systemPrompt = bootstrap(WORKSPACE_PATH)
  console.log('=== 小橙 · 个人助理 Agent ===')
  console.log('演示上下文管理：Bootstrap + 剪枝 + 压缩')
  console.log(`[Bootstrap] System prompt loaded`)
  console.log(`[Config] Token threshold: ${TOKEN_THRESHOLD}`)
  console.log('输入 exit 退出\n')

  const messages = []
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  })

  const ask = () => {
    const tokenInfo = lastPromptTokens > 0 ? lastPromptTokens : '—'
    rl.question(`[Tokens: ${tokenInfo} / ${TOKEN_THRESHOLD}] You: `, async input => {
      if (input.trim() === 'exit') return rl.close()

      messages.push({ role: 'user', content: input.trim() })

      try {
        const reply = await chat(messages, systemPrompt)
        messages.push({ role: 'assistant', content: reply })
        console.log(`\nAgent: ${reply}\n`)
      } catch (e) {
        console.error(`\nError: ${e.message}\n`)
      }

      ask()
    })
  }

  ask()
}

main()
